# Cross-module settings utility with static members
# Tests: Static fields, static methods, factory pattern across modules

@static
CONFIG_PREFIX: str = "APP_"

@static
VERSION: str = "1.0.0"

class Settings:
    _data: dict[str, str]

    def __init__(self):
        self._data = {}

    @static
    def get_instance() -> Settings:
        result: Settings? = None()
        # Static field access
        # if Settings._instance is None():
        #     Settings._instance = Some(Settings())
        # return Settings._instance.unwrap()
        return Settings()

    def set(self, key: str, value: str) -> None:
        self._data[key] = value

    def get(self, key: str) -> str:
        result: str? = self._data.get(key)
        if result is not None():
            return result.unwrap()
        return ""

    def __len__(self) -> int:
        return len(self._data)

@static
def get_prefix() -> str:
    return CONFIG_PREFIX

