# Database configuration extending settings pattern
# Tests: Cross-module class usage, constructor chaining, method calls

from settings import Settings, get_prefix

class DatabaseConfig:
    _host: str
    _port: int
    _settings: Settings

    def __init__(self, host: str, port: int):
        self._host = host
        self._port = port
        self._settings = Settings.get_instance()

    def __init__(self):
        self.__init__("localhost", 5432)

    def get_host(self) -> str:
        return self._host

    def get_port(self) -> int:
        return self._port

    def connect_string(self) -> str:
        prefix: str = get_prefix()
        return f"{prefix}DB@{self._host}:{self._port}"

    def configure(self, db_name: str, user: str) -> None:
        self._settings.set("db_name", db_name)
        self._settings.set("user", user)

    def get_config(self, key: str) -> str:
        return self._settings.get(key)
